import React from "react";
import resumePdf from "../assets/resume.pdf";

function Resume() {
  return (
    <div className="section-shell">
      <div className="section-heading">
        <p className="eyebrow">Resume</p>
        <h2>Download my resume</h2>
      </div>

      <div className="content-card resume-card">
        <p>
          You can download my resume to review my education, project exposure,
          internship experience, and technical profile in a clean format.
        </p>
        <a className="primary-button" href={resumePdf} download>
          Download Resume
        </a>
      </div>
    </div>
  );
}

export default Resume;
